document.addEventListener("alpine:init",()=>{Alpine.data("navbar",()=>({activeSection:window.location.hash.replace("#","")||"about",init(){this.highlightActiveLink(),window.addEventListener("scroll",()=>{this.highlightActiveLink()},{passive:!0}),window.addEventListener("hashchange",()=>{const i=window.location.hash.replace("#","");i&&(this.activeSection=i)})},highlightActiveLink(){const i=document.querySelectorAll("main section"),t=window.scrollY;i.forEach(i=>{const e=i.offsetTop-70,n=i.offsetHeight;t>=e&&t<e+n&&(this.activeSection=i.id)})}}))});